import React,{useState} from "react";
import {useNavigate} from "react-router-dom";

export default function Login(){
const [email, setEmail] = useState("");
const [password, setPassword] = useState("");
const [error, setError] = useState("");
const navigate = useNavigate();

function handleLogin(){
if(!email || !password){
setError("Please fill all fields");
return;
}
if(email==="admin@gmail.com"&&password==="1234"){
localStorage.setItem("user", JSON.stringify({email}));
navigate("/dash");
setError("");
} else {
setError("Invalid credentials");
}
}

const handleKeyPress = (e) => {
if(e.key === "Enter") handleLogin();
};

return(
<div className="login-container">
<div className="login-card">
<div className="text-center mb-4">
<h1 className="login-title">
<i className="bi bi-graph-up"></i> KAS
</h1>
<p className="login-subtitle">Knowledge Analytics System</p>
</div>

<div className="login-form">
<div className="mb-3">
<label className="form-label">Email Address</label>
<input 
type="email"
className="form-control" 
placeholder="admin@gmail.com" 
value={email}
onChange={(e)=>setEmail(e.target.value)}
onKeyPress={handleKeyPress}
/>
</div>

<div className="mb-3">
<label className="form-label">Password</label>
<input 
type="password"
className="form-control" 
placeholder="Enter password" 
value={password}
onChange={(e)=>setPassword(e.target.value)}
onKeyPress={handleKeyPress}
/>
</div>

{error && <div className="alert alert-danger alert-sm"><i className="bi bi-exclamation-circle-fill"></i> {error}</div>}

<button className="btn btn-primary btn-lg" onClick={handleLogin} style={{width: '100%', marginTop: '20px'}}>
<i className="bi bi-lock"></i> Sign In
</button>

<div style={{marginTop: '20px', textAlign: 'center', fontSize: '13px', color: '#64748b'}}>
<p style={{marginBottom: '0'}}>Demo credentials:<br/><strong>admin@gmail.com</strong> / <strong>1234</strong></p>
</div>
</div>
</div>
</div>
);
}
